  "inlineSchema": "// ============================================================\n// SCHEMA PRISMA — Sistema de gestión dietética familiar\n// ============================================================\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ─────────────────────────────────────────\n// USUARIOS Y ROLES\n// ─────────────────────────────────────────\n\nmodel Rol {\n  id       Int       @id @default(autoincrement())\n  nombre   String    @unique // \"empleado\" | \"administrador\"\n  usuarios Usuario[]\n\n  @@map(\"roles\")\n}\n\nmodel Usuario {\n  id            Int      @id @default(autoincrement())\n  nombre        String\n  email         String   @unique\n  passwordHash  String   @map(\"password_hash\")\n  rolId         Int      @map(\"rol_id\")\n  activo        Boolean  @default(true)\n  creadoEn      DateTime @default(now()) @map(\"creado_en\")\n  actualizadoEn DateTime @updatedAt @map(\"actualizado_en\")\n\n  rol              Rol               @relation(fields: [rolId], references: [id])\n  ventas           Venta[]\n  movimientosStock MovimientoStock[]\n\n  @@map(\"usuarios\")\n}\n\n// ─────────────────────────────────────────\n// CATÁLOGO DE PRODUCTOS\n// ─────────────────────────────────────────\n\nmodel Categoria {\n  id        Int        @id @default(autoincrement())\n  nombre    String     @unique\n  productos Producto[]\n\n  @@map(\"categorias\")\n}\n\nmodel Producto {\n  id            Int      @id @default(autoincrement())\n  nombre        String\n  categoriaId   Int      @map(\"categoria_id\")\n  marca         String?\n  descripcion   String?\n  precioCompra  Decimal  @map(\"precio_compra\") @db.Decimal(12, 2)\n  precioVenta   Decimal  @map(\"precio_venta\") @db.Decimal(12, 2)\n  stockActual   Int      @default(0) @map(\"stock_actual\")\n  stockMinimo   Int      @default(0) @map(\"stock_minimo\")\n  unidad        String   @default(\"unidades\") // kg, g, unidades, litros, ml, etc.\n  activo        Boolean  @default(true)\n  creadoEn      DateTime @default(now()) @map(\"creado_en\")\n  actualizadoEn DateTime @updatedAt @map(\"actualizado_en\")\n\n  categoria        Categoria         @relation(fields: [categoriaId], references: [id])\n  ventas           Venta[]\n  movimientosStock MovimientoStock[]\n\n  @@map(\"productos\")\n}\n\n// ─────────────────────────────────────────\n// VENTAS\n// ─────────────────────────────────────────\n\nmodel Venta {\n  id            Int      @id @default(autoincrement())\n  productoId    Int      @map(\"producto_id\")\n  cantidad      Int\n  precioVenta   Decimal  @map(\"precio_venta\") @db.Decimal(12, 2)\n  precioCompra  Decimal  @map(\"precio_compra\") @db.Decimal(12, 2) // snapshot al momento de la venta\n  ganancia      Decimal  @db.Decimal(12, 2) // (pv - pc) * cantidad\n  usuarioId     Int      @map(\"usuario_id\")\n  fecha         DateTime @default(now())\n  observaciones String?\n\n  producto Producto @relation(fields: [productoId], references: [id])\n  usuario  Usuario  @relation(fields: [usuarioId], references: [id])\n\n  @@map(\"ventas\")\n}\n\n// ─────────────────────────────────────────\n// MOVIMIENTOS DE STOCK\n// ─────────────────────────────────────────\n\nmodel MovimientoStock {\n  id               Int            @id @default(autoincrement())\n  productoId       Int            @map(\"producto_id\")\n  tipo             TipoMovimiento // INGRESO | VENTA | AJUSTE\n  cantidad         Int // positivo = ingreso, negativo = egreso\n  stockAnterior    Int            @map(\"stock_anterior\")\n  stockPosterior   Int            @map(\"stock_posterior\")\n  precioReferencia Decimal?       @map(\"precio_referencia\") @db.Decimal(12, 2)\n  usuarioId        Int            @map(\"usuario_id\")\n  fecha            DateTime       @default(now())\n  observaciones    String?\n  ventaId          Int?           @map(\"venta_id\") // FK opcional, si el movimiento es de una venta\n\n  producto Producto @relation(fields: [productoId], references: [id])\n  usuario  Usuario  @relation(fields: [usuarioId], references: [id])\n\n  @@map(\"movimientos_stock\")\n}\n\nenum TipoMovimiento {\n  INGRESO\n  VENTA\n  AJUSTE\n}\n",
